const Plugin = require("./../src/models/plugin");
const { exec } = require("child_process");

class AwsEcrLogin extends Plugin {
  name() {
    return "AWS ECR Login";
  }

  description() {
    return "Configure AWS CLI credentials and login to AWS ECR via Docker.";
  }

  icon() {
    return "☁️";
  }

  iconBase64() {
    return "data:image/png;base64,";
  }

  tags() {
    return ["aws", "ecr", "docker"];
  }

  paramsDefinition() {
    return [
      {
        name: "AWS Access Key ID",
        alias: "aws_access_key_id",
        type: "string",
        default: undefined,
        value: undefined,
      },
      {
        name: "AWS Secret Access Key",
        alias: "aws_secret_access_key",
        type: "string",
        default: undefined,
        value: undefined,
      },
      {
        name: "AWS Region",
        alias: "aws_region",
        type: "string",
        default: "eu-west-3",
        value: undefined,
      },
      {
        name: "AWS Account ID",
        alias: "aws_account_id",
        type: "string",
        default: undefined,
        value: undefined,
      },
      {
        name: "Timeout (ms)",
        alias: "timeout",
        type: "number",
        default: 30000,
        value: undefined,
      },
      {
        name: "Ignore Timeout",
        alias: "ignore_timeout",
        type: "boolean",
        default: false,
        value: undefined,
      },
    ];
  }

  async logic(params = {}) {
    const accessKeyId =
      params.aws_access_key_id || (params.input && params.input.aws_access_key_id);
    const secretAccessKey =
      params.aws_secret_access_key || (params.input && params.input.aws_secret_access_key);
    const region =
      params.aws_region || (params.input && params.input.aws_region) || "eu-west-3";
    const accountId =
      params.aws_account_id || (params.input && params.input.aws_account_id);
    const timeout = params.ignore_timeout ? 0 : (parseInt(params.timeout, 10) || 30000);

    if (!accessKeyId) {
      return {
        status: { error: true, message: "AWS Access Key ID is required" },
        output: {},
      };
    }

    if (!secretAccessKey) {
      return {
        status: { error: true, message: "AWS Secret Access Key is required" },
        output: {},
      };
    }

    if (!accountId) {
      return {
        status: { error: true, message: "AWS Account ID is required" },
        output: {},
      };
    }

    const ecrUrl = `${accountId}.dkr.ecr.${region}.amazonaws.com`;

    // Pass credentials via environment variables to avoid exposing them
    // in process arguments, shell history, or logs
    const env = {
      ...process.env,
      AWS_ACCESS_KEY_ID: accessKeyId,
      AWS_SECRET_ACCESS_KEY: secretAccessKey,
      AWS_DEFAULT_REGION: region,
    };

    try {
      this.log("Logging into AWS ECR...");
      const loginCmd = `aws ecr get-login-password --region ${region} | docker login --username AWS --password-stdin ${ecrUrl}`;
      const loginResult = await this._exec(loginCmd, timeout, env);

      this.log("ECR login successful");

      return {
        status: { error: false, message: "ECR login successful" },
        output: {
          ecr_url: ecrUrl,
          login_stdout: loginResult.stdout,
        },
      };
    } catch (err) {
      return {
        status: { error: true, message: err.message },
        output: { stdout: err.stdout || "", stderr: err.stderr || "" },
      };
    }
  }

  _exec(command, timeout, env) {
    return new Promise((resolve, reject) => {
      const child = exec(command, { timeout, env }, (error, stdout, stderr) => {
        if (error) {
          error.stdout = stdout;
          error.stderr = stderr;
          reject(error);
        } else {
          resolve({ stdout: stdout.trim(), stderr: stderr.trim() });
        }
      });
      child.stdout.on("data", (data) => {
        this.log(data.toString().trim());
      });
      child.stderr.on("data", (data) => {
        this.log(data.toString().trim(), "error");
      });
    });
  }
}

module.exports = AwsEcrLogin;
